import r from"./Base.mjs";export default Neo.setupClass(class extends r{static config={className:"Neo.data.connection.Stream",ntype:"connection-stream",compression:null};abortController=null;abort(){this.abortController?.abort()}async read(r){let e=this,o=e.url||r?.url;if(!o)throw new Error("No URL specified for connection.Stream");e.abortController=new AbortController;try{const r=await fetch(o,{signal:e.abortController.signal});if(!r.ok)throw new Error(`HTTP error! status: ${r.status}`);if(!r.body)throw new Error("ReadableStream not supported in this environment.");let t=r.body;if(e.compression){if("undefined"==typeof DecompressionStream)throw new Error("DecompressionStream not supported in this environment.");t=t.pipeThrough(new DecompressionStream(e.compression))}return{response:r,stream:t,total:parseInt(r.headers.get("content-length")||0,10)}}catch(r){if("AbortError"===r.name)return{aborted:!0};throw r}}});